1	// Shared URL-state helper for list views (artifacts, etc.).
2	// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
3	// filters.*) while preserving any unrelated keys, including ?back=.
4	
5	export type GroupBy = 'folder' | 'prefix' | 'mediaType'
6	
7	// Reserved facet URL keys (TD-006 facet contract):
8	//   q          — full-text search query (single)
9	//   mediaType  — media-type filter (single, supports X/* wildcard)
10	//   staleness  — staleness filter (single)
11	//   phase      — HELIX phase filter (single)
12	//   prefix     — id-prefix filter (multi: comma-separated)
13	//   sort       — sort key (single)
14	// groupBy is a Story-5 categorization axis (not a filter) and travels in
15	// the same URL but does NOT narrow results.
16	const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness', 'phase', 'prefix'])
17	const FILTER_PREFIX = 'filter.'
18	
19	export interface ListURLState {
20		q: string
21		mediaType: string | null
22		groupBy: GroupBy
23		sort: string | null
24		staleness: string | null
25		phase: string | null
26		prefix: string[]
27		filters: Record<string, string>
28	}
29	
30	export const DEFAULT_GROUP_BY: GroupBy = 'folder'
31	
32	function parseGroupBy(raw: string | null): GroupBy {
33		if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder') return raw
34		return DEFAULT_GROUP_BY
35	}
36	
37	export function readState(params: URLSearchParams): ListURLState {
38		const filters: Record<string, string> = {}
39		for (const [k, v] of params.entries()) {
40			if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v
41		}
42		const rawPrefix = params.get('prefix')
43		const prefix = rawPrefix
44			? rawPrefix
45					.split(',')
46					.map((s) => s.trim())
47					.filter((s) => s.length > 0)
48			: []
49		return {
50			q: params.get('q') ?? '',
51			mediaType: params.get('mediaType'),
52			groupBy: parseGroupBy(params.get('groupBy')),
53			sort: params.get('sort'),
54			staleness: params.get('staleness'),
55			phase: params.get('phase'),
56			prefix,
57			filters
58		}
59	}
60	
61	// writeState mutates a copy of `params` with the patch applied. Unrelated
62	// keys (including `back`) are preserved. Empty/null values delete the key.
63	export function writeState(
64		params: URLSearchParams,
65		patch: Partial<ListURLState>
66	): URLSearchParams {
67		const next = new URLSearchParams(params)
68	
69		if ('q' in patch) {
70			if (patch.q) next.set('q', patch.q)
71			else next.delete('q')
72		}
73		if ('mediaType' in patch) {
74			if (patch.mediaType) next.set('mediaType', patch.mediaType)
75			else next.delete('mediaType')
76		}
77		if ('groupBy' in patch) {
78			if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy)
79			else next.delete('groupBy')
80		}
81		if ('sort' in patch) {
82			if (patch.sort) next.set('sort', patch.sort)
83			else next.delete('sort')
84		}
85		if ('staleness' in patch) {
86			if (patch.staleness) next.set('staleness', patch.staleness)
87			else next.delete('staleness')
88		}
89		if ('phase' in patch) {
90			if (patch.phase) next.set('phase', patch.phase)
91			else next.delete('phase')
92		}
93		if ('prefix' in patch) {
94			const arr = patch.prefix ?? []
95			if (arr.length > 0) next.set('prefix', arr.join(','))
96			else next.delete('prefix')
97		}
98		if ('filters' in patch && patch.filters) {
99			// Replace only the filter.* keys; leave everything else intact.
100			for (const k of Array.from(next.keys())) {
101				if (k.startsWith(FILTER_PREFIX)) next.delete(k)
102			}
103			for (const [k, v] of Object.entries(patch.filters)) {
104				if (v) next.set(FILTER_PREFIX + k, v)
105			}
106		}
107	
108		return next
109	}
110	
111	// Build a back-href that captures the current pathname + relevant search.
112	export function backHref(pathname: string, params: URLSearchParams): string {
113		const s = params.toString()
114		return s ? `${pathname}?${s}` : pathname
115	}
116	
117	export { KNOWN_KEYS, FILTER_PREFIX }
