253	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
254		if (typeof input === 'string') {
255			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
256		}
257		if (input instanceof URL) {
258			return input.pathname === '/graphql';
259		}
260		return new URL(input.url).pathname === '/graphql';
261	}
262	
263	async function requestBodyText(
264		input: Parameters<typeof globalThis.fetch>[0],
265		init?: Parameters<typeof globalThis.fetch>[1]
266	): Promise<string | null> {
267		if (typeof init?.body === 'string') {
268			return init.body;
269		}
270		if (input instanceof Request) {
271			return input.clone().text();
272		}
273		return null;
274	}
275	
276	function fallbackGraphQLResponse(data: object): Response {
277		return new Response(JSON.stringify({ data }), {
278			status: 200,
279			headers: { 'content-type': 'application/json' }
280		});
281	}
282	
283	function delegateInputFor(
284		input: Parameters<typeof globalThis.fetch>[0]
285	): Parameters<typeof globalThis.fetch>[0] {
286		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
287			return input;
288		}
289		if (typeof input === 'string' || input instanceof URL) {
290			return '/graphql';
291		}
292		return input;
293	}
294	
295	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
296		const delegate = fetchFn ?? globalThis.fetch;
297		return async (input, init) => {
298			const delegateInput = delegateInputFor(input);
299			const response = await delegate(delegateInput, init);
300			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
301				return response;
302			}
303	
304			const bodyText = await requestBodyText(input, init);
305			if (!bodyText) {
306				return response;
307			}
308	
309			let body: { query?: string };
310			try {
311				body = JSON.parse(bodyText) as { query?: string };
312			} catch {
313				return response;
314			}
315	
316			const data = body.query ? fallbackDataForQuery(body.query) : null;
317			return data ? fallbackGraphQLResponse(data) : response;
318		};
319	}
320	
321	/**
322	 * Creates a GraphQL HTTP client for queries and mutations.
323	 *
324	 * Pass the SvelteKit-provided `fetch` in load functions so requests
325	 * respect SvelteKit's SSR/CSR fetch instrumentation.
326	 */
327	export function createClient(fetchFn?: typeof globalThis.fetch): GraphQLClient {
328		const url =
329			typeof window !== 'undefined' ? new URL('/graphql', window.location.href).href : '/graphql';
330		return new GraphQLClient(url, { fetch: withStaticPreviewFallback(fetchFn) });
331	}
