// Helpers for rendering FederationNode status across the federation UI.
// Maps the spoke status string (registered, active, stale, offline, degraded)
// to the existing badge-status-* CSS classes so each state has a distinct
// visual treatment.

export type FederationStatus = 'registered' | 'active' | 'stale' | 'offline' | 'degraded' | string

export function federationBadgeClass(status: string): string {
	switch (status) {
		case 'active':
			return 'badge-status-closed'
		case 'stale':
			return 'badge-status-in-progress'
		case 'degraded':
			return 'badge-status-blocked'
		case 'offline':
			return 'badge-status-failed'
		case 'registered':
			return 'badge-status-open'
		default:
			return 'badge-status-neutral'
	}
}

export function isVersionSkew(lastError: string | null | undefined): boolean {
	if (!lastError) return false
	const e = lastError.toLowerCase()
	return e.includes('version') || e.includes('skew') || e.includes('schema')
}

import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

export const FEDERATION_NODES_QUERY = gql`
	query FederationNodes {
		federationNodes {
			id
			nodeId
			name
			url
			status
			ddxVersion
			schemaVersion
			capabilities
			registeredAt
			lastHeartbeat
			writeCapability
			lastError
		}
	}
`

export interface FederationNode {
	id: string
	nodeId: string
	name: string
	url: string
	status: string
	ddxVersion: string
	schemaVersion: string
	capabilities: string[]
	registeredAt: string
	lastHeartbeat: string | null
	writeCapability: boolean
	lastError: string | null
}

interface QueryResult {
	federationNodes: FederationNode[]
}

export const load: PageLoad = async ({ fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	try {
		const data = await client.request<QueryResult>(FEDERATION_NODES_QUERY)
		return { nodes: data.federationNodes, error: null as string | null }
	} catch (e) {
		return { nodes: [] as FederationNode[], error: (e as Error).message }
	}
}

